func TestNovelSpendBehavior(t *testing.T) {
	receipts := []costcoReceipt{
		{TransactionDate: "2025-01-15", WarehouseName: "Seattle", Total: 100, DocumentType: "warehouse",
			ItemArray: []costcoItem{{DepartmentNumber: "14", Amount: 60}, {DepartmentNumber: "20", Amount: 40}}},
		{TransactionDate: "2025-01-28", WarehouseName: "Seattle", Total: 50, DocumentType: "warehouse",
			ItemArray: []costcoItem{{DepartmentNumber: "14", Amount: 50}}},
		{TransactionDate: "2025-02-03", WarehouseName: "Kirkland", Total: 200, DocumentType: "warehouse",
			ItemArray: []costcoItem{{DepartmentNumber: "20", Amount: 200}}},
	}

	t.Run("by month sums receipt totals", func(t *testing.T) {
		rows, err := aggregateSpend(receipts, "month")
		if err != nil {
			t.Fatal(err)
		}
		got := map[string]float64{}
		for _, r := range rows {
			got[r.Key] = r.Total
		}
		if got["2025-01"] != 150 || got["2025-02"] != 200 {
			t.Fatalf("month totals = %v, want 2025-01=150 2025-02=200", got)
		}
	})

	t.Run("by warehouse sums and sorts desc", func(t *testing.T) {
		rows, err := aggregateSpend(receipts, "warehouse")
		if err != nil {
			t.Fatal(err)
		}
		if len(rows) != 2 || rows[0].Key != "Kirkland" || rows[0].Total != 200 {
			t.Fatalf("warehouse rows = %+v, want Kirkland first at 200", rows)
		}
	})

	t.Run("by department sums line items", func(t *testing.T) {
		rows, err := aggregateSpend(receipts, "department")
		if err != nil {
			t.Fatal(err)
		}
		got := map[string]float64{}
		for _, r := range rows {
			got[r.Key] = r.Total
		}
		if got["14"] != 110 || got["20"] != 240 {
			t.Fatalf("department totals = %v, want 14=110 20=240", got)
		}
	})

	t.Run("invalid dimension errors", func(t *testing.T) {
		if _, err := aggregateSpend(receipts, "phase-of-moon"); err == nil {
			t.Fatal("expected error for invalid --by")
		}
	})
}
